exercises.solution:
def report(units)
  live = units.select { |u| u[:online] }
  {
    online: live.count,
    total_hp: live.reduce(0) { |sum, u| sum + u[:hp] },
    strongest: live.max_by { |u| u[:hp] }[:name],
  }
end
